1	import {
2		Controller,
3		Delete,
4		Get,
5		HttpCode,
6		HttpStatus,
7		Param,
8		Post,
9		Query,
10		Res,
11	} from '@nestjs/common';
12	import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';
13	
14	import { CurrentUser } from '@modules/auth/decorators/current-user.decorator';
15	import { Roles } from '@modules/auth/decorators/roles.decorator';
16	import { IRequestUser } from '@modules/auth/types/auth.interface';
17	import { EnvConfigService } from '@modules/env-config/env-config.service';
18	import { JiraInstallService } from '@modules/jira/jira-install.service';
19	
20	import { FRONTEND_URL } from '@constants/env-variables.constant';
21	
22	import { LogExecution } from '@decorators/log-execution.decorator';
23	
24	import type { FastifyReply } from 'fastify';
25	
26	@ApiTags('Jira Integration')
27	@Controller('integrations/jira')
28	export class JiraController {
29		constructor(
30			private readonly jiraInstallService: JiraInstallService,
31			private readonly configService: EnvConfigService,
32		) {}
33	
34		@Post('connect')
35		@Roles('admin')
36		@HttpCode(HttpStatus.OK)
37		@ApiOperation({ summary: 'Initiate Jira OAuth connection' })
38		@ApiResponse({ status: HttpStatus.OK, description: 'Returns Atlassian OAuth URL' })
39		@LogExecution()
40		async connect(@CurrentUser() user: IRequestUser): Promise<{ url: string }> {
41			// eslint-disable-next-line @typescript-eslint/no-non-null-assertion
42			const companyId = user.company_id!;
43			const url = await this.jiraInstallService.initiateConnect({
44				companyId,
45				userId: user.user_id,
46			});
47			return { url };
48		}
49	
50		@Get('callback')
51		@Roles('admin')
52		@HttpCode(HttpStatus.FOUND)
53		@ApiOperation({ summary: 'Jira OAuth callback' })
54		@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirects to frontend' })
55		@LogExecution()
56		async callback(
57			@Query() query: { code: string; state: string },
58			@Res() reply: FastifyReply,
59		): Promise<void> {
60			const frontendUrl = this.configService.get<string>({ key: FRONTEND_URL });
61	
62			try {
63				await this.jiraInstallService.handleCallback({
64					code: query.code,
65					state: query.state,
66				});
67	
68				await reply.redirect(
69					`${frontendUrl}/settings/integrations?connected=jira`,
70					HttpStatus.FOUND,
71				);
72			} catch {
73				await reply.redirect(
74					`${frontendUrl}/settings/integrations?error=jira_connect_failed`,
75					HttpStatus.FOUND,
76				);
77			}
78		}
79	
80		@Delete('installations/:id')
81		@Roles('admin')
82		@HttpCode(HttpStatus.NO_CONTENT)
83		@ApiOperation({ summary: 'Disconnect Jira installation' })
84		@ApiResponse({ status: HttpStatus.NO_CONTENT, description: 'Installation disconnected' })
85		@LogExecution()
86		async disconnect(
87			@Param() params: { id: string },
88			@CurrentUser() user: IRequestUser,
89		): Promise<void> {
90			// eslint-disable-next-line @typescript-eslint/no-non-null-assertion
91			const companyId = user.company_id!;
92			await this.jiraInstallService.disconnect({
93				installationDbId: params.id,
94				companyId,
95			});
96		}
97	}
